export const totalProducts = 156;
export const totalCategories = 22;

// Flat list of all products for search / detail lookup
export const allProducts: CatalogProduct[] = catalog.flatMap((c) => c.products);

export function findProduct(id: string): CatalogProduct | undefined {
  return allProducts.find((p) => p.id === id);
}

// Group categories by their high-level group for segregated display
export const categoryGroups: { group: string; categories: CatalogCategory[] }[] = (() => {
  const order: string[] = [];
  const map: Record<string, CatalogCategory[]> = {};
  for (const c of catalog) {
    if (!map[c.group]) { map[c.group] = []; order.push(c.group); }
    map[c.group].push(c);
  }
  return order.map((group) => ({ group, categories: map[group] }));
})();
